----------------------------------------------------------------
---@class LUIHeroAniActor
local LUIHeroAniActor = LxClass("LUIHeroAniActor",nil)
----------------------------------------------------------------
-----------------------------------------------------------------
function LUIHeroAniActor:LUIHeroAniActor(obj)
	---@type LUIHeroObject
	self._obj = obj

	self._endTime = 0

	self._bWaitEnd = false
end

------------------------------------------------------------------
function LUIHeroAniActor:OnRun(time)
	if not self._bWaitEnd then return end
	if self._endTime < time then
		self:ResetIdle()
	end
end

-----------------------------------------------------------------
function LUIHeroAniActor:PlayAni(ani,loop,aniTime,timescale,mixTime,rePlay,finishAniName)
	aniTime = aniTime or 0
	self._bWaitEnd = false
	if aniTime > 0 then
		self._endTime = Time.time + aniTime
		--self._bWaitEnd = true
	end
	timescale = timescale or 1
	local dpObj = self._obj:GetDpObject()
	dpObj:SetAnimationTimeScale(timescale)

	local gray = ani == "calm"

	local bgDpObj = self._obj:GetBgDpObject()
	if bgDpObj then
		bgDpObj:SetAnimationTimeScale(timescale)
	end

	local hdDpObj = self._obj:GetHdDpObject()
	if hdDpObj then
		hdDpObj:SetAnimationTimeScale(timescale)
	end

	if self._ani ~= ani or self._loop ~= loop or rePlay then
		local finishCB
		if not string.isempty(finishAniName) then
			finishCB = function(playSp,aniName)
				playSp:PlayAnimationSolid(aniName,true,true)
			end
		end
		local func = function()
			dpObj:SetUISpineGray(gray)
			--dpObj:PlayAnimation(0,ani,loop,true,mixTime)
			dpObj:PlayAnimationSolid(ani,loop,true)
		end
		self._obj:SetClickDpCB(function()
			if finishCB then
				finishCB(dpObj,finishAniName)
			end
		end)
		if dpObj:IsDpValid() then
			func()
		else
			self._obj:SetDPLoadFinish(func)
		end
		
		
		if bgDpObj then
			local bgAniTime = LxResPathUtil.GetSpineAniTime(bgDpObj:GetSpineName(), ani, 0)
			if bgAniTime > 0 then
				local playAniFunc = function()
					dpObj:SetUISpineGray(gray)
					--bgDpObj:PlayAnimation(0,ani,loop,true,mixTime)
					bgDpObj:PlayAnimationSolid(ani,loop,true)
				end
				self._obj:SetClickBgDpCB(function()
					if finishCB then
						finishCB(bgDpObj,finishAniName)
					end
				end)
				if bgDpObj:IsDpValid() then
					playAniFunc()
				else
					self._obj:SetBgSpineLoadCb(playAniFunc)
				end
			end
		end
		
		
		if hdDpObj then
			local hdAniTime = LxResPathUtil.GetSpineAniTime(hdDpObj:GetSpineName(), ani, 0)
			if hdAniTime > 0 then
				local playAniFunc = function()
					--hdDpObj:PlayAnimation(0,ani,loop,true,mixTime)
					hdDpObj:PlayAnimationSolid(ani,loop,true)
				end
				self._obj:SetClickHdDpCB(function()
					if finishCB then
						finishCB(hdDpObj,finishAniName)
					end
				end)
				if hdDpObj:IsDpValid() then
					playAniFunc()
				else
					self._obj:SetHdSpineLoadCb(playAniFunc)
				end
			end
		end
	end
	self._loop = loop
	self._ani = ani
end
-----------------------------------------------------------------
function LUIHeroAniActor:IsAni(ani)
	return self._ani == ani
end

function LUIHeroAniActor:ResetIdle()
	self._bWaitEnd = false
	local dpObj = self._obj:GetDpObject()
	self._obj:PlayIdleAni()
end

-----------------------------------------------------------------
function LUIHeroAniActor:Destroy()
	self._obj = nil
end

return LUIHeroAniActor